SELECT result_summary
FROM measurement_analyses
WHERE analysis_id = 1;

SELECT result_summary
FROM measurement_analyses
WHERE measurement_id = 1;

SELECT standard_implementation_notes
FROM experiment_standards
WHERE experiment_id = 0;

SELECT additional_data
FROM measurement_results
WHERE measurement_id = 1 AND result_type = 'Primary';

SELECT COUNT(*) 
FROM measurement_analyses 
WHERE analysis_type = 'Statistical Analysis';

SELECT report_title
FROM measurement_reports
WHERE report_format = 'PDF';
